parameters.jsonBody:
={{ {
  "content": (function(){
    const b = $json.body ?? $json;
    const items = (b.items || []).slice(0,5);
    const lines = items.map(i => {
      const sc = (i.score ?? '');
      const v = (i.v !== null && i.v !== undefined) ? ('V ' + Number(i.v).toFixed(1)) : '';
      const arc = (i.arc !== null && i.arc !== undefined) ? ('arc ' + Number(i.arc).toFixed(2) + 'd') : '';
      const nobs = (i.nobs !== null && i.nobs !== undefined) ? ('obs ' + i.nobs) : '';
      return `• ${i.desig} (prio ${i.priority}, score ${sc}) — ${[v,nobs,arc].filter(Boolean).join(', ')}`;
    }).join('\n');
    const hdr = `PDF MPC NEOCP TRIAGE: ${b.new_count ?? items.length} new object(s)`;
    const src = b.source ? (`Source: ${b.source}`) : '';
    return [hdr, lines, src].filter(Boolean).join('\n');
  })()
} }}
